exercises.solution_code:
#include <iostream>

auto applyTransform(int offset, int scale) {
    return [offset, scale](int x) {
        return x * scale + offset;
    };
}

int main() {
    int offset{};
    int scale{};
    int x{};
    std::cin >> offset >> scale >> x;

    auto fn{ applyTransform(offset, scale) };
    std::cout << fn(x) << '\n';

    return 0;
}

