exercises.solution_code:
#include <iostream>
#include <vector>

int main() {
    int n{};
    int threshold{};
    std::cin >> n >> threshold;

    std::vector<int> nums(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> nums[i];

    int totalCount{ 0 };

    auto filter{ [threshold, &totalCount](int val) {
        if (val > threshold) {
            std::cout << val << '\n';
            ++totalCount;
        }
    } };

    for (int val : nums)
        filter(val);

    std::cout << "Count: " << totalCount << '\n';

    return 0;
}
